function nodeJson(name) {
  const n = $(name);
  if (!n.isExecuted) return null;
  const item = n.first();
  return item ? item.json : null;
}

const config = nodeJson('Config NeoTravel') ?? {};
const status = nodeJson('GET status');
const qualifier = nodeJson('POST qualifier');
const calculer = nodeJson('POST calculer-devis');
const generer = nodeJson('POST generer-devis');
const relance = nodeJson('POST relance');
const incomplete = nodeJson('Demande incomplète');
const isDemo = $('▶ Démo jury').isExecuted;

const statusBody = status?.body ?? status;
const relanceTraitees = relance?.traitees ?? 0;
const devisGenere = !!generer?.devis_id;

return [{
  json: {
    execution_summary: {
      at: new Date().toISOString(),
      service: 'neotravel-orchestration',
      mode: isDemo ? 'demo_jury' : 'schedule_relances',
      app_url: config.app_url,
      storage_backend: statusBody?.storage_backend ?? null,
      api_reachable: statusBody?.ok === true,
      pending_relances_at_start: statusBody?.pending_relances ?? null,
      qualifier: qualifier ? {
        demande_id: qualifier.demande_id,
        pret_pour_devis: qualifier.pret_pour_devis,
        score: qualifier.score_completude,
        error: qualifier.error ?? qualifier.erreur ?? null,
        missing: qualifier.missing ?? qualifier.champs_manquants ?? null
      } : null,
      incomplete_message: incomplete?.message ?? null,
      calcul: calculer?.prix_ttc ? { prix_ttc: calculer.prix_ttc, prix_ht: calculer.prix_ht } : (calculer?.erreur ? { error: calculer.erreur } : null),
      devis: devisGenere ? {
        devis_id: generer.devis_id,
        prix_ttc: generer.prix_ttc,
        email_sent: generer.email_sent,
        relances_planifiees: generer.email_sent ? '2 relances client planifiées (échéance future)' : 'aucune (pas d\'email client)'
      } : null,
      relances: relance ? {
        ok: relance.ok ?? null,
        traitees: relanceTraitees,
        note: devisGenere && relanceTraitees === 0
          ? 'Normal juste après generer-devis : relances pas encore échues (cron 15 min ou DEMO_MODE)'
          : (incomplete ? 'Branche incomplète — relance non appelée' : null)
      } : null
    }
  }
}];
